const Q_ECONOMICS_2012=[{"id": "objective>Economics>2012>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What subject is this?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Economics.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Government.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Commerce</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The question is asking about the subject of the question itself. Given that the question is categorized under 'Economics' as indicated by the id, the correct answer is option 1, 'Economics.'</div>", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS"}, {"id": "objective>Economics>2012>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major disadvantage of a socialist economy is that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">corruption is rampant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">consumers' sovereignty is lost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">income inequality is entrenched</div>", "<div style=\"font-family:Cambria;font-size:17px;\">there is high level of unemployment</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a socialist economy, the government owns and controls the means of production. This means that the government decides what goods and services to produce, how to produce them, and who gets them. This leads to a loss of consumers' sovereignty, which is the power of consumers to decide what goods and services are produced based on their demands. The other options are not inherent disadvantages of a socialist economy.</div>", "topic": "ECONOMIC SYSTEM : ECONOMIC PROBLEMS OF THE SOCIETY"}, {"id": "objective>Economics>2012>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The privatization of public enterprises will lead to efficient management of resources in the economy. This statement can best be described as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">normative reasoning</div>", "<div style=\"font-family:Cambria;font-size:17px;\">inductive reasoning</div>", "<div style=\"font-family:Cambria;font-size:17px;\">deductive reasoning</div>", "<div style=\"font-family:Cambria;font-size:17px;\">positive reasoning.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The statement is an example of normative reasoning. Normative reasoning involves value judgments or subjective statements about what ought to be or what things are desirable. It is based on opinions and personal values. The statement is suggesting that privatization 'should' lead to efficient management, which is a value judgment. Inductive reasoning, deductive reasoning, and positive reasoning are all types of logical reasoning that deal with facts and cause-and-effect relationships, not value judgments.</div>", "topic": "INDUSTRY & INDUSTRIALISATION : COMMERCIALISATION & PRIVATISATION"}, {"id": "objective>Economics>2012>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The sign of the slope of a graph in economic analysis is important because it</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">shows whether a good is normal or inferior</div>", "<div style=\"font-family:Cambria;font-size:17px;\">shows the relationship between variables</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reveals the magnitude of the change between variables</div>", "<div style=\"font-family:Cambria;font-size:17px;\">helps to determine the unit of measurement of variables. </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Shows the relationship between variables. Upward slope shows a positive while a downward slope shows a negative relationship respectively.</div>", "topic": "TOOLS FOR ECONOMIC ANALYSIS : SCIENTIFIC APPROACH"}, {"id": "objective>Economics>2012>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><p style=\"padding: 3px;\"> Use the diagram beside to answer the question below </p>  <br/>  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The percentage contribution of agriculture is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">67.5  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">40.0  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">32.4  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">25.0 </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The percentage contribution of agriculture is  <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Agric</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">90<hr size=\"1\" />360</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100<hr size=\"1\" />5</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">25</td></tr></table></div></div>", "topic": "AGRICULTURE IN WEST AFRICA : INTRODUCTION"}, {"id": "objective>Economics>2012>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\"> Use the diagram beside to answer the question below </p>  <br/>  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> If the GDP is ₦60 billion, what is the difference between the contributions of oil and manufacturing sectors? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦11.7 billion  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦13.3 billion  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦21.7 billion  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦26.6 billion </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Manufacturing = 360-(90+160+30)=80 <br/>  difference in angle between oil and manufacturing=160-80=80  <br/>  Hence difference i contribution between the two sectors=80/360 × 60billion  <br/> = 13.33billion.</div>", "topic": "AGRICULTURE IN WEST AFRICA : INTRODUCTION"}, {"id": "objective>Economics>2012>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the quantity of rice bought decreases from 250 tonnes to 200 tonnes owing to a 2% rise in price, it shows that there is a change in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Consumers' income</div>", "<div style=\"font-family:Cambria;font-size:17px;\">demand</div>", "<div style=\"font-family:Cambria;font-size:17px;\">consumers' tastes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">quantity demanded.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The change in the quantity of rice bought from 250 tonnes to 200 tonnes due to a 2% rise in price is a change in quantity demanded. Quantity demanded refers to the total amount of a good or service that consumers are willing and able to purchase at a given price. In this case, as the price of rice increased, the quantity demanded decreased, which is a typical behavior according to the law of demand.</div>", "topic": "THE THEORY OF DEMAND : DISTINCTION BETWEEN CHANGE IN QUANTITY DEMANDED AND CHANGE IN DEMAND"}, {"id": "objective>Economics>2012>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A rise in income will, ceteris paribus, bring about</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a movement along the demand curve</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a leftward shift of the demand curve</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a rightward shift of the demand curve</div>", "<div style=\"font-family:Cambria;font-size:17px;\">no effect on the demand curve</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">There is an increase in demand when the demand curve shift to the right.  The rightward shift is due to : increase in consumers income, rising price of substitutes, effectiving advert, population size  etc.</div>", "topic": "THE THEORY OF DEMAND : DISTINCTION BETWEEN CHANGE IN QUANTITY DEMANDED AND CHANGE IN DEMAND"}, {"id": "objective>Economics>2012>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">From the table below, calculate the price elasticity of demand.  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Price (₦)</td><td style=\"border:1px solid black;text-align:center;\"> Quantity (kg) <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">50</td><td style=\"border:1px solid black;text-align:center;\"> 500 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">70</td><td style=\"border:1px solid black;text-align:center;\"> 400</td></tr></table></div></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">50   </div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.0   </div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.0   </div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.5 </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">ED</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">% Δ in Q<hr size=\"1\" />% Δ in P</td></tr></table></div>  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">% Δ in Q</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">500 - 400<hr size=\"1\" />500</td><td style=\"text-align:center;\"> ×</td><td style=\"text-align:center;\">100</td></tr></table></div>  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">% Δ in Q</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">100<hr size=\"1\" />400</td><td style=\"text-align:center;\"> ×</td><td style=\"text-align:center;\">100 </td><td style=\"text-align:center;\"> = 20%</td></tr></table></div>  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">% Δ in P</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">70 - 50<hr size=\"1\" />50</td><td style=\"text-align:center;\"> ×</td><td style=\"text-align:center;\">100</td></tr></table></div>  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">% Δ in Q</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">20<hr size=\"1\" />50</td><td style=\"text-align:center;\"> ×</td><td style=\"text-align:center;\">100 </td><td style=\"text-align:center;\"> = 40%</td></tr></table></div>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">ED</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">20<hr size=\"1\" />40</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">= </td><td style=\"text-align:center;\">0.5</td></tr></table></div></div>", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND"}, {"id": "objective>Economics>2012>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the price of an item increases by 8% while the quantity demanded falls from 1500 units to 1492 units, the demand is said to be </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">perfectly elastic </div>", "<div style=\"font-family:Cambria;font-size:17px;\">inelastic </div>", "<div style=\"font-family:Cambria;font-size:17px;\">elastic </div>", "<div style=\"font-family:Cambria;font-size:17px;\">perfectly inelastic</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">% Δ in Q</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1500 - 1492<hr size=\"1\" />1492</td><td style=\"text-align:center;\"> ×</td><td style=\"text-align:center;\">100</td></tr></table></div>  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">% Δ in Q</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">8<hr size=\"1\" />1492</td><td style=\"text-align:center;\"> ×</td><td style=\"text-align:center;\">100 </td><td style=\"text-align:center;\"> = 0.54</td></tr></table></div>  <br/>  % Δ P = 8  <br/>  P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">ED</span> = 0.54/8 = 0.0675 }</div>", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND"}, {"id": "objective>Economics>2012>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Comparison of interpersonal utility is impossible because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">utility is measured in utils</div>", "<div style=\"font-family:Cambria;font-size:17px;\">marginal utility is not observable</div>", "<div style=\"font-family:Cambria;font-size:17px;\">utility is subjectively determined</div>", "<div style=\"font-family:Cambria;font-size:17px;\">individual income differ</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The comparison of interpersonal utility is impossible because utility is subjectively determined. This means that utility, or the satisfaction that a person gets from consuming a good or service, is based on individual preferences and personal circumstances. Therefore, it is not possible to compare the utility of one person with that of another.</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : UTILITY SCHOOL OF THOUGHT"}, {"id": "objective>Economics>2012>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When the shape of the total utility curve is declining, the marginal utility of a consumer will be increasing if he</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">stops consuming more of the commodity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduces the quantity consumed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">consumes more of another commodity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">consumes more of another commodity.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"> Marginal utility refers to the additional satisfaction a consumer derives from the consumption of an additional unit of a product. As more and more of a product is consumed by that consumer, the utility/satisfaction he gets reduces.   <br/> Therefore, the marginal utility of a product is greater when a person has fewer of them, but as the accumulation of goods increases, the marginal utility of additional goods declines.</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : DIMINISHING MARGINAL UTILITY AND LAW OF DEMAND"}, {"id": "objective>Economics>2012>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><strong>Use the diagram below to answer the question that follows</strong> <br/> <img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The consumer is at equilibrium at point </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">N   </div>", "<div style=\"font-family:Cambria;font-size:17px;\">P   </div>", "<div style=\"font-family:Cambria;font-size:17px;\">M   </div>", "<div style=\"font-family:Cambria;font-size:17px;\">K </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The consumer is at equilibrium where he maximizes satisfaction which is at point K i.e where the slope of the indifference curve is tangential to theb budget line</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : CONSUMER EQUILIBRIUM"}, {"id": "objective>Economics>2012>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <strong>Use the diagram below to answer the question that follows</strong> <br/> <img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The move from point M to K, the consumer has to increase the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">consumption of X and reduce the consumption of Y</div>", "<div style=\"font-family:Cambria;font-size:17px;\">expenditure Y</div>", "<div style=\"font-family:Cambria;font-size:17px;\">expenditure on X</div>", "<div style=\"font-family:Cambria;font-size:17px;\">consumption of Y and reduce the consumption of X.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The indifference curve joins all the possible combinations of y & x given the budget constraint. Opportunity cost applies here, in order to increase consumption of Y, the consumption of X has to be reduced</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : CONSUMER EQUILIBRIUM"}, {"id": "objective>Economics>2012>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The supply of cocoa is influenced by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">seasonal conditions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the efficacy of fertilizer used</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the demand for beverages</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the availability of close substitutes.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The supply of a commodity like cocoa is influenced by various factors. One of the key factors is seasonal conditions. Cocoa is a crop that depends on specific weather conditions for its growth. Therefore, changes in weather patterns or seasonal conditions can significantly affect the supply of cocoa. The efficacy of fertilizer used, the demand for beverages, and the availability of close substitutes can also influence the supply of cocoa, but they are not as direct or significant as seasonal conditions.</div>", "topic": "AGRICULTURE IN WEST AFRICA : FEATURES"}, {"id": "objective>Economics>2012>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If quantity is constant irrespective of price changes, the supply elasticity is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">unitary </div>", "<div style=\"font-family:Cambria;font-size:17px;\">infinity </div>", "<div style=\"font-family:Cambria;font-size:17px;\">fairly elastic </div>", "<div style=\"font-family:Cambria;font-size:17px;\">perfectly inelastic</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Elasticity of supply measures the responsiveness of quantity supplied to a change in price. If the quantity supplied remains constant irrespective of price changes, it means the supply is perfectly inelastic. In this case, suppliers are not responsive to price changes.</div>", "topic": "THEORY OF SUPPLY : ELASTICITY OF SUPPLY"}, {"id": "objective>Economics>2012>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The cost elasticity of supply is a useful instrument for measuring</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Profit </div>", "<div style=\"font-family:Cambria;font-size:17px;\">productivity </div>", "<div style=\"font-family:Cambria;font-size:17px;\">national income</div>", "<div style=\"font-family:Cambria;font-size:17px;\">price index</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The price/cost elasticity of supply measures the degree to which a change in price would affect the quantity of goods the producer is willing to produce and supply.</div>", "topic": "THE CONCEPT OF COST & REVENUE : THE MARGINAL COST & SUPPLY CURVE OF A FIRM"}, {"id": "objective>Economics>2012>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The invisible hand promotes the interests of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Consumers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">society </div>", "<div style=\"font-family:Cambria;font-size:17px;\">government</div>", "<div style=\"font-family:Cambria;font-size:17px;\">producers</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">According to Adam Smith, the working of the invisible hand is to the benefit of the society. Investing in an industry with the aim of making a profit represents an \"invisible\" hand where the interests of the society are promoted while enriching the person who has made the investment.</div>", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS"}, {"id": "objective>Economics>2012>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Fixing price above equilibrium will cause</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">demand and supply to remain constant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in quantity supplied</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a decrease in quantity supplied.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Fixing prices above equilibrium will cause an increase in supply because suppliers will be willing to produce more since they will sell at a high price</div>", "topic": "THE THEORY OF PRICE DETERMINATION : DETERMINANTS OF PRICE UNDER FREE MARKET"}, {"id": "objective>Economics>2012>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An important function of the price system is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ensure that producers' profits remain high</div>", "<div style=\"font-family:Cambria;font-size:17px;\">guarantee full employment of resources</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Allocate resources to most productive uses</div>", "<div style=\"font-family:Cambria;font-size:17px;\">protect the economic interests of government.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Allocate resources to most productive uses. The price signals producers on the quantity to produce. Hence using available resources to produce the quantity of goods in demand.</div>", "topic": "THE THEORY OF PRICE DETERMINATION : CONCEPT OF MARKET AND PRICE"}, {"id": "objective>Economics>2012>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If all factors are variable in the long run, firm will experience</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">decreasing returns to scale</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increasing returns to scale</div>", "<div style=\"font-family:Cambria;font-size:17px;\">diminishing returns</div>", "<div style=\"font-family:Cambria;font-size:17px;\">economies of scale</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the long run, all factors of production are variable. This means that a firm can adjust all its inputs in response to changes in market conditions. This flexibility allows the firm to achieve economies of scale, which refers to the cost advantages that firms obtain due to size, output, or scale of operation, with cost per unit of output generally decreasing with increasing scale as fixed costs are spread out over more units of output. Therefore, the correct answer is 'economies of scale'.</div>", "topic": "THEORY OF PRODUCTION (2) : PRODUCTION FUNCTIONS & LAWS OF RETURNS"}, {"id": "objective>Economics>2012>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The equilibrium point of a firm is attained at the point where the isoquant is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">greater than the isocost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">less the the isocost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tangent to the isocost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">greater than the output</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The firm is in equilibrium at the point where the isoquant curve is tangent to the iso-cost line. At this point, the firm is maximising its output level by employing the optimal combination of capital and labour.</div>", "topic": "THEORY OF PRODUCTION (2) : PRODUCERS EQUILIBRIUM"}, {"id": "objective>Economics>2012>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The long-run average cost curve touches the short-run average cost curve at the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">minimum points of all short-run average cost curves</div>", "<div style=\"font-family:Cambria;font-size:17px;\">declining points of all short-run average cost curves</div>", "<div style=\"font-family:Cambria;font-size:17px;\">minimum point of only one of the short-run curves</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rising points of all short-run average cost curves.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Long-Run Average Cost (LRAC) curve is derived from a series of Short-Run Average Cost (SRAC) curves. It is often called the envelope curve because it envelopes or touches each SRAC curve at exactly one point — specifically at the minimum point of the SRAC where the firm is optimally using plant size or scale for that level of output. <br/>  <br/> At this point, the firm's plant size (fixed inputs) is perfectly suited to the level of production, so the short-run and long-run costs are equal.</div>", "topic": "THE CONCEPT OF COST & REVENUE : SHORT RUN & LONG RUN COST"}, {"id": "objective>Economics>2012>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a firm doubles all inputs in the long run and the total output is less than doubled, this results in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">diminishing returns</div>", "<div style=\"font-family:Cambria;font-size:17px;\">constant returns to scale</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increasing returns to scale</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decreasing returns to scale</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Decreasing Returns to Scale. Decreasing returns to scale occur when a firm's output less than scales in comparison to its inputs. For example, a firm exhibits decreasing returns to scale if its output less than doubles when all of its inputs are doubled. </div>", "topic": "THEORY OF PRODUCTION (2) : PRODUCTION FUNCTIONS & LAWS OF RETURNS"}, {"id": "objective>Economics>2012>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Patents and copyrights enable monopolists to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">determine the quality of their products</div>", "<div style=\"font-family:Cambria;font-size:17px;\">determine the sale of their products</div>", "<div style=\"font-family:Cambria;font-size:17px;\">restrict information flow to new firms</div>", "<div style=\"font-family:Cambria;font-size:17px;\">restrict entry of new firms.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Restricts entry of new firms. Patent rights prevents any other firm from producing exactly the same type of machine.</div>", "topic": "MARKET STRUCTURE : IMPERFECT MARKET ( MONOPOLY)"}, {"id": "objective>Economics>2012>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A discriminatory monopoly is characterized by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a common elasticity in different markets</div>", "<div style=\"font-family:Cambria;font-size:17px;\">different elasticities in different markets</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a finite elasticity in all markets</div>", "<div style=\"font-family:Cambria;font-size:17px;\">zero elasticity in all markets.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Different elasticities in different markets. It exists where the same product is sold at different prices to different buyers e.g Business class & economy class in the same aircraft.</div>", "topic": "MARKET STRUCTURE : IMPERFECT MARKET ( MONOPOLY)"}, {"id": "objective>Economics>2012>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Net National Product is derived by deducting</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">net exports from GNP</div>", "<div style=\"font-family:Cambria;font-size:17px;\">subsidies from NNP</div>", "<div style=\"font-family:Cambria;font-size:17px;\">taxes from GDP</div>", "<div style=\"font-family:Cambria;font-size:17px;\">depreciation from GNP </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Net National Product (NNP) is derived by deducting depreciation from Gross National Product (GNP). Depreciation refers to the wear and tear of capital goods over a period of time. So, when we subtract the depreciation from GNP, we get NNP which represents the net output of the economy after accounting for the depreciation of capital goods.</div>", "topic": "NATIONAL INCOME : CONCEPT"}, {"id": "objective>Economics>2012>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><p style=\"padding: 3px;\"> Use the information below to answer the question below </p>  <br/>  <br/> The investment expenditure of an economy changes by ₦2million and MPC is 0.75. <br/>  <br/> What is the change in income?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> ₦0.5m </div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦81.5m </div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦2.6m </div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦8.0m</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The change in income is calculated using the multiplier effect. The formula for the multiplier is 1/(1-MPC). Given that the MPC is 0.75, the multiplier is 4. Therefore, the change in income is the change in investment expenditure multiplied by the multiplier, which is ₦2million * 4 = ₦8million.</div>", "topic": "EQUILIBRIUM LEVEL OF NATIONAL INCOME : THE CONCEPT OF MULTIPLIER"}, {"id": "objective>Economics>2012>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\"> Use the information below to answer the question below </p>  <br/>  <br/> The investment expenditure of an economy changes by ₦2million and MPC is 0.75. <br/> The multiplier is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">8 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">4 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">3 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">2</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The multiplier is calculated as 1/(1-MPC). Given that the MPC is 0.75, the multiplier is 4.</div>", "topic": "EQUILIBRIUM LEVEL OF NATIONAL INCOME : THE CONCEPT OF MULTIPLIER"}, {"id": "objective>Economics>2012>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The money that commands a higher market value than its face value is called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">paper money  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">standard money</div>", "<div style=\"font-family:Cambria;font-size:17px;\">commodity money </div>", "<div style=\"font-family:Cambria;font-size:17px;\">fiat money</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The money that commands a higher market value than its face value is called fiat money. Fiat money is money that is not backed by any physical commodity, such as gold or silver. Instead, its value is derived from the government's decree that it must be accepted as legal tender.</div>", "topic": "MONEY : TYPES OF MONEY"}, {"id": "objective>Economics>2012>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a basket of commodities costs ₦120 in the base year and ₦240 in the current year, calculate the price index.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">100</div>", "<div style=\"font-family:Cambria;font-size:17px;\">200</div>", "<div style=\"font-family:Cambria;font-size:17px;\">240</div>", "<div style=\"font-family:Cambria;font-size:17px;\">300</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Price</td><td style=\"text-align:center;\">index</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Price of current year<hr size=\"1\" />Price of previous(base) year</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100<hr size=\"1\" />1</td></tr></table></div>  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">240<hr size=\"1\" />120</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100<hr size=\"1\" />1</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">200%</td></tr></table></div></div>", "topic": "MONEY : VALUE OF MONEY"}, {"id": "objective>Economics>2012>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The minimum amount which banks are required to deposit with the central bank is determined by the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">liquidity ratio  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cash reserve ratio</div>", "<div style=\"font-family:Cambria;font-size:17px;\">minimum lending rate </div>", "<div style=\"font-family:Cambria;font-size:17px;\">aggregate credit ceiling</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cash reserve ratio (CRR)/legal reserve ratio is a certain percentage of the total deposits of the bank that must be kept in the current account with the central bank of the country, which would mean that the bank shall not have access to that amount of money for any commercial activity or economic activity.</div>", "topic": "FINANCIAL INSTITUTION : CENTRAL BANK"}, {"id": "objective>Economics>2012>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major function of the money market is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">provide funds for long-term financing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">provide funds for short-term financing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">stabilize the value of the local currency</div>", "<div style=\"font-family:Cambria;font-size:17px;\">stabilize domestic prices.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The money market is a component of the economy which provides short-term funds. The money market deals in short-term loans, generally for a period of a year or less.</div>", "topic": "FINANCIAL INSTITUTION : INTRODUCTION"}, {"id": "objective>Economics>2012>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An ad valorem tax is imposed on</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">special commodities </div>", "<div style=\"font-family:Cambria;font-size:17px;\">exports</div>", "<div style=\"font-family:Cambria;font-size:17px;\">imports   </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the value of a commodity</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An ad valorem tax is a tax that is based on the assessed value of an item such as real estate or personal property. It is more commonly applied to duties on imported goods. Therefore, the correct answer is 'the value of a commodity'.</div>", "topic": "PUBLIC FINANCE : CLASSIFICATION OF TAX"}, {"id": "objective>Economics>2012>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A huge national debt is an indication that the gold reserves of a nation has</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">appreciated</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decreased</div>", "<div style=\"font-family:Cambria;font-size:17px;\">depreciation  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">stagnated</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A large national debt does not necessarily mean that a nation has low gold reserves. However, it can put pressure on a country's gold reserves, as the country may need to sell some of its gold reserves to raise money to finance its debt.</div>", "topic": "ECONOMIC DEVELOPMENT : INDICATORS OF GROWTH & DEVELOPMENT"}, {"id": "objective>Economics>2012>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Rapid economic development in Nigeria is realizable by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">continuous dependence on oil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">concentrating more on agriculture</div>", "<div style=\"font-family:Cambria;font-size:17px;\">developing the tourism industry</div>", "<div style=\"font-family:Cambria;font-size:17px;\">diversifying the economy</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Economic diversification Economic diversification is the process of shifting an economy away from a single income source toward multiple sources from a growing range of sectors and markets. Traditionally, it has been applied as a strategy to encourage positive economic growth and development.</div>", "topic": "ECONOMIC DEVELOPMENT : DEVELOPMENT PLANNING"}, {"id": "objective>Economics>2012>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The primary reason for desiring economic growth is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">control inflation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduce poverty</div>", "<div style=\"font-family:Cambria;font-size:17px;\">redistribute income</div>", "<div style=\"font-family:Cambria;font-size:17px;\">raise standard of living.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Raise standard of living. Standard of living is the extent to which citizens can satisfy their wants and economic growth is the increase of the total output of a country over time.</div>", "topic": "ECONOMIC DEVELOPMENT : INDICATORS OF GROWTH & DEVELOPMENT"}, {"id": "objective>Economics>2012>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An emerging agriculture export crop in Nigeria is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cassava </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cotton </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cocoa </div>", "<div style=\"font-family:Cambria;font-size:17px;\">soya beans.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cassava is an emerging agriculture export crop in Nigeria. This is due to the fact that Nigeria is the world's largest producer of cassava. The government has been promoting the export of value-added cassava products like flour and starch. Therefore, the correct answer is cassava.</div>", "topic": "AGRICULTURE IN WEST AFRICA : INTRODUCTION"}, {"id": "objective>Economics>2012>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A strategy for improving agriculture in Nigeria will involve</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">controlling the prices of agriculture products</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ensuring self-sufficiency in food production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">establishing commodity boards</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reducing agricultural exports.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">One of the ways to improve agriculture in Nigeria is too first ensure self-sufficiency. Agricultural production Nigeria should be able to cater for the needs of the people before working towards exportation.  Nigeria should be able to maintain oneself or itself without outside aid.</div>", "topic": "AGRICULTURE IN WEST AFRICA : ROLES"}, {"id": "objective>Economics>2012>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A sugar industry is best located near the source of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">labour</div>", "<div style=\"font-family:Cambria;font-size:17px;\">raw materials</div>", "<div style=\"font-family:Cambria;font-size:17px;\">power</div>", "<div style=\"font-family:Cambria;font-size:17px;\">capital</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A sugar industry is best located near the source of raw materials. This is because the raw materials for sugar production, which are sugarcane or sugar beets, are bulky and perishable. Transporting them over long distances can be costly and may lead to spoilage. Therefore, to minimize transportation costs and prevent spoilage, it is best to locate the industry near the source of the raw materials.</div>", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION"}, {"id": "objective>Economics>2012>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An important contribution of small scale industries to the Nigerian economy is in the area of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">technological development</div>", "<div style=\"font-family:Cambria;font-size:17px;\">foreign exchange earnings</div>", "<div style=\"font-family:Cambria;font-size:17px;\">raw materials processing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">labour employment</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">According to the Nigeria Bureau of Statistics, small and medium scale enterprises (SMEs) in Nigeria have contributed about 48% of the national GDP in the last five years. With a total number of about 17.4 million, they account for about 50% of industrial jobs and nearly 90% of the manufacturing sector, in terms of number of enterprises.</div>", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION"}, {"id": "objective>Economics>2012>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A change in the pump price of petrol in Nigeria has a direct effect on the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">prices of consumer goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">prices of essential goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cost of raw materials</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cost of transportation.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A change in the pump price of petrol in Nigeria has a direct effect on the cost of transportation. This is because petrol is a major fuel used in transportation. When the price of petrol increases, the cost of transportation also increases because transporters would need to spend more on petrol. This is a basic economic principle that when the cost of an input (in this case, petrol) increases, the cost of the product or service (in this case, transportation) that uses that input also increases.</div>", "topic": "INFLATION & DEFLATION : EFFECT"}, {"id": "objective>Economics>2012>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Long-term fund of investment projects are sourced from the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">money market</div>", "<div style=\"font-family:Cambria;font-size:17px;\">commodity market</div>", "<div style=\"font-family:Cambria;font-size:17px;\">foreign exchange market</div>", "<div style=\"font-family:Cambria;font-size:17px;\">capital market.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Long-term funds for investment projects are sourced from the capital market. The capital market is a part of the financial market where long-term debt or equity-backed securities are bought and sold. It is where businesses and governments can raise long-term funds. It is divided into two categories, primary and secondary markets. The primary market is where new securities are sold for the first time, while the secondary market is where existing securities are traded.</div>", "topic": "FINANCIAL INSTITUTION : DEVELOPMENT, MERCHANT, MORTGAGE BANK ETC"}, {"id": "objective>Economics>2012>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A policy aimed at enhancing globalization of the Nigerian economy is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">indigenization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">deregulation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">commercialization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">privatization.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Deregulation is a policy aimed at enhancing globalization of the Nigerian economy. Deregulation is the process of removing or reducing state regulations, typically in the economic sphere. It is the repeal of governmental regulation of the economy. It became common in advanced industrial economies in the 1970s and 1980s, as a result of new trends in economic thinking about the inefficiencies of government regulation, and the risk that regulatory agencies would be controlled by the regulated industry to its benefit, and thereby hurt consumers and the wider economy.</div>", "topic": "INDUSTRY & INDUSTRIALISATION : COMMERCIALISATION & PRIVATISATION"}, {"id": "objective>Economics>2012>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Malthusian Theory was concerned about the relationship between</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">population growth rates of the rich and the poor nations</div>", "<div style=\"font-family:Cambria;font-size:17px;\">population density and national income</div>", "<div style=\"font-family:Cambria;font-size:17px;\">population growth rate and natural resources</div>", "<div style=\"font-family:Cambria;font-size:17px;\">age distribution of population.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Malthusian theory of population examines the relationship between population growth and food supply. It states that the population grows exponentially, while its food supply only grows at a linear rate. That eventually causes the population to outgrow its food supply, which leads to a Malthusian crisis.</div>", "topic": "POPULATION : THEORIES OF POPULATION"}, {"id": "objective>Economics>2012>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a village of 50 persons, 10 immigrated, 25 died and 5 emigrated in a year. Determine the total population.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">10  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">20 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">30 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">50</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Total population = Birth rate - Death rate + Net migration  <br/> Where net migration = Immigrant - Emigrant <br/>                                   = 25 - ( 10-5) <br/>                                          = 25 - 5 <br/>                                                = 20 <br/> Therefore, total population = 50 - 20 <br/>                                                    = 30  </div>", "topic": "POPULATION : DETERMINANTS OF POPULATION SIZE"}, {"id": "objective>Economics>2012>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A deficit balance is measured by subtracting the debits from the credits in the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">current account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">current and capital accounts</div>", "<div style=\"font-family:Cambria;font-size:17px;\">current and escrow accounts</div>", "<div style=\"font-family:Cambria;font-size:17px;\">capital and escrow accounts.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A deficit balance is calculated by subtracting the debits from the credits. In the context of economics, this is typically done in the current account, which records a nation's transactions with the rest of the world, specifically its net trade in goods and services, its net earnings on cross-border investments, and its net transfer payments. Therefore, the correct answer is 'current account'.</div>", "topic": "INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT"}, {"id": "objective>Economics>2012>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the functions of ECOWAS is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">provide funds for infrastructural development</div>", "<div style=\"font-family:Cambria;font-size:17px;\">determine prices of exports</div>", "<div style=\"font-family:Cambria;font-size:17px;\">redistribute income among citizens</div>", "<div style=\"font-family:Cambria;font-size:17px;\">provide employment for citizens of member nations.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">ECOWAS was also set up to promote the idea of collective self-sufficiency among the states. As a trading union, it is also meant to create a single, large trading bloc through economic cooperation among the member states. ECOWAS also functions as a peacekeeping force amongst member states.</div>", "topic": "INTERNATIONAL ECONOMIC ORGANISATION : OPEC, ECA, IMF"}, {"id": "objective>Economics>2012>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The reward on machinery and equipment in the process of production is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">profit </div>", "<div style=\"font-family:Cambria;font-size:17px;\">interest </div>", "<div style=\"font-family:Cambria;font-size:17px;\">rent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">wages </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Capital' - investment in man-made aids to production including buildings, factories, computers. The reward for capital is interest. <br/>  <br/> Interest is the payment made for the use of borrowed money. In the context of production, interest is the reward paid to the owner of capital, which includes machinery and equipment.</div>", "topic": "FACTORS OF PRODUCTION & THEIR THEORIES : RENT & INTEREST"}, {"id": "objective>Economics>2012>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">From the diagram below, the minimum wage OW will lead to  <br/>  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">full employment of resources</div>", "<div style=\"font-family:Cambria;font-size:17px;\">unemployment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">inflation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">full employment of factors of production.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The minimum wage tends to create an excess of supply over demand when this occurs businesses will have to lay of workers leading to unemployment.</div>", "topic": "LABOUR MARKET AND UNEMPLOYMENT : THE CONCEPT OF UNEMPLOYMENT"}];
